import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setClientData(null);
    window.location.reload(); 
  };

  return (
    <div className="home-page">

      {/* Hero Section - आपकी इमेज के कलर के साथ */}
      <header 
        className="py-5 text-white" 
        style={{ 
          backgroundColor: '#24478f', // आपकी इमेज वाला सटीक नीला रंग
          minHeight: '60vh',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center'
        }}
      >
        <div className="container text-center">
          <div className="row justify-content-center">
            <div className="col-lg-8">
              
              {/* लैपटॉप आइकन */}
              <div className="mb-4">
                 <img 
                  src="https://cdn-icons-png.flaticon.com" 
                  alt="Laptop Icon" 
                  style={{ width: '80px', filter: 'brightness(0) invert(1)' }} 
                />
              </div>

              {/* मुख्य हेडिंग */}
              <h1 className="display-3 fw-bold mb-3">
                Web Development
              </h1>

              <p className="lead fs-4 mb-4 opacity-90">
                Professional services by talented student freelancers.
              </p>

              {/* पीला बटन */}
              <Link 
                to="/services" 
                className="btn btn-lg px-5 fw-bold shadow-sm"
                style={{ backgroundColor: '#ffc107', color: '#000', borderRadius: '8px', border: 'none' }}
              >
                Explore Services
              </Link>
            </div>
          </div>
        </div>
      </header>

      {/* Features Cards Section */}
      <section className="py-5 bg-light">
        <div className="container">
          <div className="row text-center">
            
            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '45px' }}>🛡️</div>
                  <h5 className="fw-bold text-primary">Secure Payments</h5>
                  <p className="text-muted">Safe and reliable transactions for every project.</p>
                </div>
              </div>
            </div>

            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '45px' }}>🎓</div>
                  <h5 className="fw-bold text-primary">Verified Students</h5>
                  <p className="text-muted">Work with skilled and verified student experts.</p>
                </div>
              </div>
            </div>

            <div className="col-md-4 mb-4">
              <div className="card shadow-sm h-100 border-0 rounded-4 p-4">
                <div className="card-body">
                  <div className="mb-3" style={{ fontSize: '45px' }}>⚡</div>
                  <h5 className="fw-bold text-primary">Fast Delivery</h5>
                  <p className="text-muted">Get your web projects completed on time.</p>
                </div>
              </div>
            </div>

          </div>
        </div>
      </section>

      {/* Map Section - Nashik Location */}
      <section id="contact" className="py-5 bg-white">
        <div className="container py-5 text-center">
          <h2 className="fw-bold mb-5">📍 Our Location (Nashik)</h2>
          <div className="row justify-content-center">
            <div className="col-lg-10">
              <div className="shadow-lg rounded-4 overflow-hidden" style={{ height: '400px', border: '1px solid #ddd' }}>
                <iframe
                  title="Nashik Map"
                  src="https://www.google.com"
                  width="100%"
                  height="100%"
                  style={{ border: 0 }}
                  allowFullScreen=""
                  loading="lazy"
                ></iframe>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Footer */}
      <footer className="py-4 bg-dark text-white text-center">
        <p className="mb-0">&copy; 2026 Student Freelancer Marketplace | Nashik, Maharashtra</p>
      </footer>

    </div>
  );
}

export default Home;
